import{_ as a,c as s,a1 as n,o as t}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Footprinting basics with Windows command line","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/1-Windows-CommandLine.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/1-Windows-CommandLine.md"}'),i={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/1-Windows-CommandLine.md"};function o(p,e,r,c,d,l){return t(),s("div",null,e[0]||(e[0]=[n(`<h1 id="footprinting-basics-with-windows-command-line" tabindex="-1">Footprinting basics with Windows command line <a class="header-anchor" href="#footprinting-basics-with-windows-command-line" aria-label="Permalink to &quot;Footprinting basics with Windows command line&quot;">​</a></h1><p>The objective of this tutorial is teach the basics of Footprinting methodologies, used for ethical-hackers and pentesters.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Virtual environment</li><li>Windows 8.1/10</li><li>Windows Server 2012 or 2016</li><li>Basics of networking</li></ul><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Use ping command to find the IP address of target domain.</li><li>Use ping command to emulate the traceroute (tracert command).</li><li>Discover the maximum frame size for the network.</li><li>ICMP type and the code for echo request and echo reply packets.</li></ul><h2 id="commands-used-on-this-tutorial" tabindex="-1">Commands used on this tutorial <a class="header-anchor" href="#commands-used-on-this-tutorial" aria-label="Permalink to &quot;Commands used on this tutorial&quot;">​</a></h2><h2 id="ping" tabindex="-1"><code>ping</code> <a class="header-anchor" href="#ping" aria-label="Permalink to &quot;\`\`\`ping\`\`\`&quot;">​</a></h2><p>The ping command sends ICMP (Internet Control Message Protocol) Used to test the reachability of a host on a IP network and measures the travel time for messages sent from the originating host to destinantion target.</p><h2 id="nslookup" tabindex="-1"><code>nslookup</code> <a class="header-anchor" href="#nslookup" aria-label="Permalink to &quot;\`\`\`nslookup\`\`\`&quot;">​</a></h2><p>Used for querying the DNS (Domain Name System), to obtain a domain name or IP address mapping and other specific DNS record.</p><h2 id="tracert-windows-or-traceroute-linux" tabindex="-1"><code>tracert</code> (Windows) or <code>traceroute</code> (Linux) <a class="header-anchor" href="#tracert-windows-or-traceroute-linux" aria-label="Permalink to &quot;\`\`\`tracert\`\`\` (Windows) or \`\`\`traceroute\`\`\` (Linux)&quot;">​</a></h2><p>Diagnostic tool for displaying the route and measuring transit delays of packets across an IP network</p><p><strong>NOTE:</strong><strong>I strongly recommend you to use the -help command to specify all parameters of a given command</strong></p><p><code>ping -help</code></p><hr><h2 id="finding-the-ip-address-of-http-www-certifiedhacker-com" tabindex="-1">Finding the IP address of <a href="http://www.certifiedhacker.com" target="_blank" rel="noreferrer">http://www.certifiedhacker.com</a> <a class="header-anchor" href="#finding-the-ip-address-of-http-www-certifiedhacker-com" aria-label="Permalink to &quot;Finding the IP address of http://www.certifiedhacker.com&quot;">​</a></h2><p>Open the <strong>Command prompt</strong> or <strong>PowerShell</strong> on Windows and type:</p><p><code>ping www.certifiedhacker.com</code></p><p>The response should be similiar to the message below. Note: The IP address may differ in your environment.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reply from 162.241.216.11: bytes=32 time=160ms TTL=40</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=151ms TTL=40</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=151ms TTL=40</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=153ms TTL=40</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 4, Received = 4, Lost = 0 (0% loss)</span></span>
<span class="line"><span>Approximate round trip times in milli-seconds:</span></span>
<span class="line"><span>    Minimum = 151ms, Maximum = 160ms, Average = 153ms</span></span></code></pre></div><hr><h2 id="finding-the-maximum-frame-size-on-the-network" tabindex="-1">Finding the maximum frame size on the network <a class="header-anchor" href="#finding-the-maximum-frame-size-on-the-network" aria-label="Permalink to &quot;Finding the maximum frame size on the network&quot;">​</a></h2><p>Use the last command and add the <code>-f</code> parameter to not fragment on the ping packet and <code>-l</code> to set the frame size to <code>1500</code> bytes.</p><p><code>ping www.certifiedhacker.com -f -l 1500</code></p><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Packet needs to be fragmented but DF set.</span></span></code></pre></div><p>This message above means that the frame is too large to be on the network and needs to be fragmented.</p><p>The propose here is to try different values until you reach the maximum frame size.</p><p><strong>Example:</strong></p><p><code> ping www.certifiedhacker.com -f -l 1450</code><em>working</em><code> ping www.certifiedhacker.com -f -l 1475</code><em>reached the limit</em><code> ping www.certifiedhacker.com -f -l 1473</code><em>reached the limit</em><code> ping www.certifiedhacker.com -f -l 1472</code><em>working</em></p><p>In conclusion, note the last two replies <code>1473</code> bytes and <code>1472</code> bytes shows the <strong>maximum frame size</strong> on this machine&#39;s network.</p><hr><h2 id="investigate-the-ttl-time-to-live" tabindex="-1">Investigate the TTL (Time to Live). <a class="header-anchor" href="#investigate-the-ttl-time-to-live" aria-label="Permalink to &quot;Investigate the TTL (Time to Live).&quot;">​</a></h2><p>Every frame on the network has their own TTL defined. If the TTL reaches 0, the router discards the packet to prevent packet loss.</p><p><code>ping www.certifiedhacker.com -i 3</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span></code></pre></div><p>The <code>-i</code> parameter means wait time, that is the number of seconds to wait between each ping (values between <code>1-255</code>).</p><p>TTL expired means that the router discarded the frame, beacuse the TTL has expired (reached 0).</p><hr><h2 id="find-the-traceroute-from-your-machine-to-www-certifiedhacker-com" tabindex="-1">Find the traceroute from your machine to www.certifiedhacker.com <a class="header-anchor" href="#find-the-traceroute-from-your-machine-to-www-certifiedhacker-com" aria-label="Permalink to &quot;Find the traceroute from your machine to www.certifiedhacker.com&quot;">​</a></h2><p>This command traceroutes the network configuration information of the target domain.</p><p>Open a new window on your prompt or powershell and type:</p><p><code>tracert www.certifiedhacker.com</code></p><p>The system resolves the URL into its IP address and starts to trace the path to the destination. Here it takes 19 hops for the packet to reach the specified destination.</p><p>You can use the help flag to show different options for the command: <code>tracert /?</code></p><hr><h2 id="let-s-check-the-life-span-of-the-packet" tabindex="-1">Let&#39;s check the life span of the packet. <a class="header-anchor" href="#let-s-check-the-life-span-of-the-packet" aria-label="Permalink to &quot;Let&#39;s check the life span of the packet.&quot;">​</a></h2><p>Open a new window of your prompt or powershell and type:</p><p><code>ping www.certifiedhacker.com -i 2 -n 1</code></p><p>We are setting the TTL to <code>2</code> in an attempt to check the life span of the packet and <code>-n</code> count of packet to <code>1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pinging certifiedhacker.com [162.241.216.11] with 32 bytes of data:</span></span>
<span class="line"><span>Reply from 10.10.10.45: TTL expired in transit.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 1, Received = 1, Lost = 0 (0% loss),</span></span></code></pre></div><p>There is a reply coming from IP address 162.241.216.11 with no packet loss.</p><p>Let&#39;s set the TTL value to <code>3</code> to see what happens</p><p><code>ping www.certifiedhacker.com -i 3 -n 1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pinging certifiedhacker.com [162.241.216.11] with 32 bytes of data:</span></span>
<span class="line"><span>Reply from 10.10.127.254: TTL expired in transit.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 1, Received = 1, Lost = 0 (0% loss),</span></span></code></pre></div><p>Note there is a different IP address, the same one that we gather on the traceroute command on the first hops.</p><p>Repeat this and increase the TTL value until reach the IP address from www.certifiedhacker.com that we trace routed before.</p><p><code>ping www.certifiedhacker.com -i 19 -n 1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pinging certifiedhacker.com [162.241.216.11] with 32 bytes of data:</span></span>
<span class="line"><span>Reply from 162.241.216.11: bytes=32 time=156ms TTL=40</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ping statistics for 162.241.216.11:</span></span>
<span class="line"><span>    Packets: Sent = 1, Received = 1, Lost = 0 (0% loss),</span></span>
<span class="line"><span>Approximate round trip times in milli-seconds:</span></span>
<span class="line"><span>    Minimum = 156ms, Maximum = 156ms, Average = 156ms</span></span></code></pre></div><p>Done! These results implies when you set the TTL to 19(in this case) the reply is received from destination host (162.241.216.11). Keep in mind that the output will be similar to the trace route results.</p><p>Make a note of all the IP addresses from which you receive a reply.</p><hr><h2 id="using-nslookup-command" tabindex="-1">Using <code>nslookup</code> command <a class="header-anchor" href="#using-nslookup-command" aria-label="Permalink to &quot;Using \`\`\`nslookup\`\`\` command&quot;">​</a></h2><p>Used for querying the DNS (Domain Name System), to obtain a domain name or IP address mapping and other specific DNS record.</p><p>Type in your prompt or powershell:</p><p><code>nslookup</code></p><p><strong>Note</strong>: This command will launch a interactive mode, you can type <code>help</code> to list available commands!</p><p>For query IP address of a given domain, you need to set the <code>type</code> to <code>A</code> record, then enter the target domain:</p><p><code>&gt; type=a</code><code>&gt; www.certifiedhacker.com</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; set type=a</span></span>
<span class="line"><span>&gt; www.certifiedhacker.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Server:  dns.google</span></span>
<span class="line"><span>Address:  8.8.8.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Non-authoritative answer:</span></span>
<span class="line"><span>Name:    certifiedhacker.com</span></span>
<span class="line"><span>Address:  162.241.216.11</span></span>
<span class="line"><span>Aliases:  www.certifiedhacker.com</span></span></code></pre></div><p><strong>Note</strong>: This environment uses Google DNS server (8.8.8.8). To configure your own DNS server just type <code>server x.x.x.x</code>.</p><p>The first two lines <strong>dns.google</strong> and <strong>8.8.8.8</strong> specifies that the result was directed to this server to resolve your requested domain. Google&#39;s DNS server do not contain domain&#39;s original zone files, this is why is <strong>Non-authoritative</strong>.</p><p>The <strong>Authoritative</strong> is a name server that has the original source files of a domain zone files. To obtain the Authoritative name server, set the <code>type</code> to <code>CNAME</code> record and query the target:</p><p><code>set type=cname</code><code>certifiedhacker.com</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; set type=cname</span></span>
<span class="line"><span>&gt; certifiedhacker.com</span></span>
<span class="line"><span>Server:  dns.google</span></span>
<span class="line"><span>Address:  8.8.8.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>certifiedhacker.com</span></span>
<span class="line"><span>        primary name server = ns1.bluehost.com</span></span>
<span class="line"><span>        responsible mail addr = dnsadmin.box5331.bluehost.com</span></span>
<span class="line"><span>        serial  = 2018011205</span></span>
<span class="line"><span>        refresh = 86400 (1 day)</span></span>
<span class="line"><span>        retry   = 7200 (2 hours)</span></span>
<span class="line"><span>        expire  = 3600000 (41 days 16 hours)</span></span>
<span class="line"><span>        default TTL = 300 (5 mins)</span></span></code></pre></div><p>The <code>CNAME</code> lookup is done directly against the domain&#39;s authoritative name server.</p><p>With the authoritative name server, you can determine the IP address. To query IP address set the <code>type</code> to <code>A</code>, then type the <strong>primary name server</strong> displayed in your lab environment, in my case: <code>ns1.bluehost.com</code>.</p><p><code>set type=a</code><code>ns1.bluehost.com</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; set type=a</span></span>
<span class="line"><span>&gt; ns1.bluehost.com</span></span>
<span class="line"><span>Server:  dns.google</span></span>
<span class="line"><span>Address:  8.8.8.8</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Non-authoritative answer:</span></span>
<span class="line"><span>Name:    ns1.bluehost.com</span></span>
<span class="line"><span>Address:  162.159.24.80</span></span></code></pre></div><p>In conclusion, the <strong>Authoritative name server</strong> stores the records associated with the respective domain. Having the authoritative name server (primary name server) and the IP address associated with it, an attacker can attempt to exploit the server, performing attacks like DDoS, URL redirection and so on.</p><p><strong>Final analysis:</strong></p><ul><li>Document all the IP addresses</li><li>Reply request IP addresses</li><li>Information about TTL&#39;s</li><li>DNS server names and other DNS information.</li></ul>`,83)]))}const u=a(i,[["render",o]]);export{m as __pageData,u as default};
